mapper.select:
SELECT COALESCE(day_stats.session_count, 0) AS sessionCount, COALESCE(day_stats.visitor_count, 0) AS visitorCount, COALESCE(day_stats.known_visitor_count, 0) AS knownVisitorCount, COALESCE(day_stats.stranger_visitor_count, 0) AS strangerVisitorCount, COALESCE(open_stats.open_session_count, 0) AS openSessionCount, COALESCE(day_stats.closed_dwell_seconds, 0) AS closedDwellSeconds, COALESCE(day_stats.open_dwell_seconds, 0) AS openDwellSeconds FROM ( SELECT COUNT(*)::bigint AS session_count, COUNT(DISTINCT CASE WHEN ps.person_id IS NOT NULL THEN 'p:' || ps.person_id::text ELSE 't:' || ps.track_key END)::bigint AS visitor_count, COUNT(DISTINCT CASE WHEN ps.person_id IS NOT NULL AND p.person_type IN ('student', 'staff') THEN ps.person_id END)::bigint AS known_visitor_count, COUNT(DISTINCT CASE WHEN ps.person_id IS NULL THEN ps.track_key WHEN p.person_type = 'stranger' THEN 'p:' || ps.person_id::text END)::bigint AS stranger_visitor_count, COALESCE(SUM( CASE WHEN ps.status = 'closed' THEN ps.dwell_seconds ELSE 0 END ), 0)::bigint AS closed_dwell_seconds, COALESCE(SUM( CASE WHEN ps.status = 'open' THEN GREATEST(0, FLOOR(EXTRACT(EPOCH FROM (NOW() - ps.arrival_at))))::bigint ELSE 0 END ), 0)::bigint AS open_dwell_seconds FROM presence_sessions ps LEFT JOIN persons p ON p.id = ps.person_id
) day_stats CROSS JOIN ( SELECT COUNT(*)::bigint AS open_session_count FROM presence_sessions ps LEFT JOIN persons p ON p.id = ps.person_id
AND 1 = 0
) open_stats

SELECT c.id AS cameraId, c.device_name AS deviceName, c.serial_no AS deviceSerial, c.channel_no AS channelNo, COUNT(ps.id)::bigint AS sessionCount, COALESCE(SUM( CASE WHEN ps.id IS NULL THEN 0 WHEN ps.status = 'closed' THEN ps.dwell_seconds ELSE GREATEST(0, FLOOR(EXTRACT(EPOCH FROM (NOW() - ps.arrival_at))))::bigint END ), 0)::bigint AS dwellSeconds, COUNT(ps.id) FILTER (WHERE ps.status = 'open')::bigint AS openCount FROM camera c LEFT JOIN presence_sessions ps ON ps.camera_id = c.id AND ps.arrival_at >= AND ps.arrival_at < WHERE c.online_status = 'online'
AND c.id = #{cameraId}
GROUP BY c.id, c.device_name, c.serial_no, c.channel_no ORDER BY sessionCount DESC, c.id

SELECT x.track_key AS trackKey, COALESCE(x.display_name, '未知访客') AS displayName, fp.image_url AS face_image_url, x.person_id AS mergedPersonId FROM ( SELECT DISTINCT ON (ps.track_key) ps.track_key, ps.person_id, p.display_name, ps.arrival_at FROM presence_sessions ps LEFT JOIN persons p ON p.id = ps.person_id WHERE ps.track_key IS NOT NULL AND ps.track_key <> ''
AND ps.camera_id = #{cameraId}
AND (ps.person_id IS NULL OR p.person_type = 'stranger') ORDER BY ps.track_key, ps.arrival_at DESC ) x LEFT JOIN LATERAL ( SELECT image_url FROM face_profiles WHERE person_id = x.person_id ORDER BY created_at DESC LIMIT 1 ) fp ON x.person_id IS NOT NULL ORDER BY x.arrival_at DESC

mapper.update:
UPDATE presence_sessions
SET person_id = NULL, updated_at = NOW()
WHERE track_key = #{trackKey}

UPDATE presence_sessions
SET person_id = #{personId}, updated_at = NOW()
WHERE track_key = #{trackKey}

mapper.select:
SELECT * FROM ( SELECT p.id AS personId, p.display_name AS displayName, COALESCE(p.employee_no, '') AS employeeNo, p.person_type::text AS personKind, ll.device_name AS locationName, CASE WHEN COALESCE(sir.overlapped, FALSE) = FALSE THEN 'absent' WHEN COALESCE(sir.present_at_end, FALSE) = TRUE THEN 'present' ELSE 'left' END AS attendanceStatus, COALESCE(pc.passage_count, 0) AS passageCount, sir.first_arrival AS arrivalAt, CASE WHEN COALESCE(sir.present_at_end, FALSE) THEN NULL ELSE sir.last_departure END AS departureAt, COALESCE(sir.dwell_seconds, 0) AS dwellSeconds, COALESCE(sir.overlapped, FALSE) AS overlapped FROM persons p LEFT JOIN ( SELECT ps.person_id, BOOL_OR( ps.arrival_at < AND (ps.status = 'open' OR COALESCE(ps.departure_at, NOW()) > ) ) AS overlapped, BOOL_OR( ps.arrival_at <= AND (ps.status = 'open' OR COALESCE(ps.departure_at, NOW()) > ) ) AS present_at_end, MIN(ps.arrival_at) FILTER ( WHERE ps.arrival_at < AND (ps.status = 'open' OR COALESCE(ps.departure_at, NOW()) > ) ) AS first_arrival, MAX(ps.departure_at) FILTER ( WHERE ps.status = 'closed' AND ps.arrival_at < AND COALESCE(ps.departure_at, NOW()) > ) AS last_departure, COALESCE(SUM( CASE WHEN ps.arrival_at < AND (ps.status = 'open' OR COALESCE(ps.departure_at, NOW()) > ) THEN GREATEST(0, FLOOR(EXTRACT(EPOCH FROM ( LEAST(COALESCE(ps.departure_at, NOW()), , NOW()) - GREATEST(ps.arrival_at, ) ))))::bigint ELSE 0 END ), 0)::bigint AS dwell_seconds FROM presence_sessions ps WHERE ps.person_id IS NOT NULL
AND ps.camera_id = #{cameraId}
GROUP BY ps.person_id ) sir ON sir.person_id = p.id LEFT JOIN ( SELECT DISTINCT ON (ps.person_id) ps.person_id, c.device_name FROM presence_sessions ps INNER JOIN camera c ON c.id = ps.camera_id WHERE ps.person_id IS NOT NULL AND ps.arrival_at < AND (ps.status = 'open' OR COALESCE(ps.departure_at, NOW()) > )
AND ps.camera_id = #{cameraId}
ORDER BY ps.person_id, ps.arrival_at DESC ) ll ON ll.person_id = p.id LEFT JOIN ( SELECT bl.person_id, COUNT(*)::bigint AS passage_count FROM behavior_logs bl WHERE bl.person_id IS NOT NULL AND bl.event_type = 'enter' AND bl.event_time >= AND bl.event_time <
AND bl.camera_id = #{cameraId}
GROUP BY bl.person_id ) pc ON pc.person_id = p.id
AND p.person_type::text = #{filter.personType}
AND ( EXISTS (SELECT 1 FROM face_profiles fp WHERE fp.person_id = p.id) OR COALESCE(p.face_image_url, '') <> '' OR EXISTS ( SELECT 1 FROM presence_sessions ps2 WHERE ps2.person_id = p.id AND ps2.arrival_at < AND (ps2.status = 'open' OR COALESCE(ps2.departure_at, NOW()) > )
AND ps2.camera_id = #{cameraId}
) )
AND p.display_name ILIKE CONCAT('%', #{filter.displayName}, '%')
AND COALESCE(p.employee_no, '') ILIKE CONCAT('%', #{filter.employeeNo}, '%')
) attendance_rows
AND attendanceStatus = 'absent'
AND attendanceStatus = 'present'
AND attendanceStatus = 'left'
AND attendanceStatus = 'present'
AND attendanceStatus = 'left'
ORDER BY dwellSeconds DESC, displayName ASC LIMIT #{limit}
